
import httpx
import base64
from pathlib import Path

def test_analyze():
    # Use a dummy base64 image (small black pixel)
    dummy_b64 = "data:image/jpeg;base64,"
    
    url = "http://127.0.0.1:8000/api/ai/analyze-crop"
    payload = {
        "imageData": dummy_b64,
        "language": "en"
    }
    # Need auth token, but I'll try without first to see if it reaches the model
    try:
        resp = httpx.post(url, json=payload, timeout=30)
        print(f"Status: {resp.status_code}")
        print(f"Response: {resp.text}")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    test_analyze()
